const $ = id => document.getElementById(id);
const Prestige = {
KEY: 'snakeio_prestige_unlocked',
isUnlocked(){ return sessionStorage.getItem(this.KEY) === '1'; },
unlock(){
sessionStorage.setItem(this.KEY, '1');
this._applyUI();
},
_applyUI(){
// Déverrouiller l'option rainbow dans le skin picker
const opt = document.querySelector('.skin-opt[data-skin="rainbow"]');
if(opt) opt.classList.add('unlocked');
},
init(){
if(this.isUnlocked()) this._applyUI();
},
rainbowColor(offset=0){
const t = performance.now()/1000;
const h = ((t * 60 + offset) % 360);
return `hsl(${h},100%,55%)`;
},
rainbowColorDark(offset=0){
const t = performance.now()/1000;
const h = ((t * 60 + offset + 30) % 360);
return `hsl(${h},100%,35%)`;
},
};
const U = {
lerp:(a,b,t)=>a+(b-a)*t,
clamp:(v,mn,mx)=>Math.max(mn,Math.min(mx,v)),
rand:(a,b)=>Math.random()*(b-a)+a,
rInt:(a,b)=>Math.floor(Math.random()*(b-a+1))+a,
rAng:()=>Math.random()*Math.PI*2,
dist2:(a,b)=>{const dx=a.x-b.x,dy=a.y-b.y;return dx*dx+dy*dy},
dist:(a,b)=>Math.sqrt(U.dist2(a,b)),
ang:(a,b)=>Math.atan2(b.y-a.y,b.x-a.x),
wrapAng(a){while(a>Math.PI)a-=Math.PI*2;while(a<-Math.PI)a+=Math.PI*2;return a},
lerpAng(a,b,t){let d=b-a;while(d>Math.PI)d-=Math.PI*2;while(d<-Math.PI)d+=Math.PI*2;return a+d*t},
SKINS:{
green: {h:'#50dc50',b:'#28b428'},
blue:  {h:'#50a0ff',b:'#2870dc'},
red:   {h:'#ff5050',b:'#dc2828'},
yellow:{h:'#ffdc3c',b:'#dcb41e'},
purple:{h:'#b450ff',b:'#8228dc'},
cyan:  {h:'#3cdcdc',b:'#1ab4b4'},
},
BOT_NAMES:['Cobra','Viper','Mamba','Python','Asp','Taipan','Krait','Rattler',
'Anaconda','Shadow','Ghost','Blaze','Nova','Titan','Nexus','Venom','Specter',
'Phantom','Wraith','Storm','Fury','Apex','Chaos','Rogue','Adder','Fer-de-lance'],
rName(){return this.BOT_NAMES[this.rInt(0,this.BOT_NAMES.length-1)]},
rSkin(){const k=Object.keys(this.SKINS);return k[this.rInt(0,k.length-1)]},
};
const Music = {
on:false,
init(){
var bgm=document.getElementById('bgm');
var vi=document.getElementById('vol-init');
var vp=document.getElementById('vol-pct');
var vh=document.getElementById('vol-hud');
var ic=document.getElementById('vol-icon');
vi.addEventListener('input',function(){
vp.textContent=vi.value+'%';
vi.style.background='linear-gradient(to right,#50dc50 '+vi.value+'%,#252545 '+vi.value+'%)';
});
document.getElementById('btn-mus-on').addEventListener('click',function(){
bgm.volume=parseInt(vi.value)/100; bgm.muted=false;
bgm.play().catch(function(e){console.warn(e);});
Music.on=true; vh.value=vi.value; Music.sync();
UI.show('platform-screen');
});
document.getElementById('btn-mus-off').addEventListener('click',function(){
bgm.pause(); Music.on=false; UI.show('platform-screen');
});
vh.addEventListener('input',function(){
bgm.volume=parseInt(vh.value)/100; bgm.muted=parseInt(vh.value)===0; Music.sync();
});
ic.addEventListener('click',function(){
bgm.muted=!bgm.muted;
if(!bgm.muted&&bgm.volume===0){bgm.volume=0.4;vh.value=40;}
Music.sync();
});
},
sync(){
var bgm=document.getElementById('bgm');
var vh=document.getElementById('vol-hud');
var ic=document.getElementById('vol-icon');
var v=bgm.muted?0:Math.round(bgm.volume*100);
vh.value=v; vh.style.background='linear-gradient(to right,#50dc50 '+v+'%,#252545 '+v+'%)';
ic.textContent=v===0?'🔇':v<50?'🔉':'🔊';
},
pause(){var b=document.getElementById('bgm');if(b&&Music.on&&!b.paused)b.pause();},
resume(){var b=document.getElementById('bgm');if(b&&Music.on&&b.paused)b.play().catch(function(){});},
};
