const rg=ctx.createRadialGradient(sx-hr*.2,sy-hr*.2,0,sx,sy,hr);
rg.addColorStop(0, Prestige.rainbowColor(0));
rg.addColorStop(0.5, Prestige.rainbowColor(120));
