const WS = 8000;
class Game {
constructor(){
this.canvas=$('gc');
this.rdr=new Renderer(this.canvas,$('mm'));
this.running=false;this.paused=false;
this.player=null;this.snakes=[];this.food=null;
this.mx=innerWidth/2;this.my=innerHeight/2;
this.boosting=false;
this.lastT=0;this.startT=0;this.bestRank=1;
this._botTarget=15;
this._bindEv();
}
_bindEv(){
this.canvas.addEventListener('mousemove',e=>{this.mx=e.clientX;this.my=e.clientY});
this.canvas.addEventListener('mousedown',e=>{if(e.button===0)this.boosting=true});
window.addEventListener('mouseup',()=>this.boosting=false);
this.canvas.addEventListener('touchmove',e=>{e.preventDefault();const t=e.touches[0];this.mx=t.clientX;this.my=t.clientY},{passive:false});
this.canvas.addEventListener('touchstart',e=>{this.boosting=true;const t=e.touches[0];this.mx=t.clientX;this.my=t.clientY});
this.canvas.addEventListener('touchend',()=>this.boosting=false);
window.addEventListener('keydown',e=>{
if(e.key==='Shift'||e.key===' ')this.boosting=true;
if(e.key==='p'||e.key==='Escape')this.togglePause();
});
window.addEventListener('keyup',e=>{if(e.key==='Shift'||e.key===' ')this.boosting=false});
$('btn-pause').addEventListener('click',()=>this.togglePause());
}
start(name,skin,diff){
_DIFF = DIFF[diff] || DIFF.normal;
this.snakes=[];
this.food=new FoodMgr(WS,4000);
this.bestRank=1; this.startT=performance.now();
this._botTarget=_DIFF.botCount;
this.player=new Snake({id:'player',name,skin,x:0,y:0,isPlayer:true});
this.snakes.push(this.player);
for(let i=0;i<_DIFF.botCount;i++)this.spawnBot();
this.running=true;this.paused=false;
window.G=this;
this.lastT=performance.now();
requestAnimationFrame(t=>this.loop(t));
}
spawnBot(){
const h=WS/2-300,a=U.rAng(),d=U.rand(200,h);
const b=new Bot({id:'b'+Math.random().toString(36).slice(2),name:U.rName(),skin:U.rSkin(),x:Math.cos(a)*d,y:Math.sin(a)*d});
const il=_DIFF.initLen; b.grow(U.rInt(il[0],il[1]));
this.snakes.push(b);return b;
}
togglePause(){
if(!this.running)return;
this.paused=!this.paused;
UI.show(this.paused?'pause-screen':'game-screen');
if(this.paused){Music.pause();}else{this.lastT=performance.now();Music.resume();requestAnimationFrame(t=>this.loop(t))}
}
loop(t){
if(!this.running||this.paused)return;
const raw=(t-this.lastT)/1000;
const dt=Math.min(raw,.033);
if(raw>.5){this.lastT=t;requestAnimationFrame(ts=>this.loop(ts));return;}
this.lastT=t;
this.update(dt);
this.rdr.render({snakes:this.snakes,food:this.food,ws:WS,player:this.player});
requestAnimationFrame(ts=>this.loop(ts));
}
update(dt){
this.food.update(dt);
this.rdr.updatePtcls(dt);
if(this.player&&!this.player.dead){
if(UI.isMobile && (this._joyX||this._joyY)){
var jx=this._joyX||0, jy=this._joyY||0;
if(Math.abs(jx)>0.08||Math.abs(jy)>0.08){
this.player.targetAngle=Math.atan2(jy,jx);
}
} else {
this.player.targetAngle=Math.atan2(this.my-this.rdr.H/2,this.mx-this.rdr.W/2);
}
this.player.setBoost(this.boosting);
if(this.player.boosting){
const tl=this.player.segs[this.player.len-1];
if(tl)this.rdr.addPtcl(tl.x,tl.y,this.player.hc);
}
}
const snakeMap=new Map(this.snakes.map(s=>[s.id,s]));
const gs={food:this.food,snakes:this.snakes,snakeMap,ws:WS};
for(const s of this.snakes){
if(s.dead)continue;
const r=s.isPlayer?s.update(dt):s.update(dt,gs);
if(r?.drop)this.food.spawn(r.drop.x,r.drop.y,2);
if(!s.isPlayer&&s.boosting&&Math.random()<.25){
const tl=s.segs[s.len-1];if(tl)this.rdr.addPtcl(tl.x,tl.y,s.hc);
}
s.wrap(WS);
}
this.checkFood();
this.checkCollisions();
this.maintainBots();
Admin.tick();
this.updateHUD();
this.rdr.camUpdate(this.player?.dead?{x:0,y:0}:(this.player?.head||{x:0,y:0}),this.player?.len||6,dt);
}
checkFood(){
for(const s of this.snakes){
if(s.dead)continue;
const near=this.food.near(s.head.x,s.head.y,s.segR+14);
for(const f of near){
if(U.dist(s.head,f)<s.segR+f.r){s.grow(f.v);this.food.remove(f)}
}
}
}
checkCollisions(){
const kill=new Set();
const alive=this.snakes.filter(s=>!s.dead);
for(let i=0;i<alive.length;i++){
const a=alive[i];
if(kill.has(a.id))continue;
const ar=a.segR*0.8;
for(let j=0;j<alive.length;j++){
if(i===j)continue;
const b=alive[j];
if(kill.has(b.id))continue;
const qdx=a.head.x-b.head.x, qdy=a.head.y-b.head.y;
const qd2=qdx*qdx+qdy*qdy;
const maxR=(b.segR+ar+2); const maxRange=b.len*13+maxR;
if(qd2>maxRange*maxRange)continue;
const br=b.segR*0.8, r=(ar+br)*(ar+br);
const step=Math.max(1,Math.floor(b.segs.length/30));
for(let k=1;k<b.segs.length;k+=k<60?1:step){
if(U.dist2(a.head,b.segs[k])<r){kill.add(a.id);this.addKill(b.name,a.name);break}
}
if(kill.has(a.id))break;
}
}
for(const s of alive)if(kill.has(s.id)&&!(s.isPlayer&&Admin.godMode))this.killSnake(s);
}
killSnake(s){
s.dead=true;
this.food.spawnDeath(s.head.x,s.head.y,Math.floor(s.len*.6));
if(s.isPlayer){
this.running=false;
FakeLB.recordScore(s.score, s.len);
const elapsed=Math.floor((performance.now()-this.startT)/1000);
setTimeout(()=>UI.showDeath(s.score,this.bestRank,elapsed),700);
}
}
addKill(killer,victim){
const kf=$('kf');
while(kf.children.length>=5)kf.removeChild(kf.firstChild);
const el=document.createElement('div');
el.className='kfi';el.textContent=killer+' 💀 '+victim;
kf.appendChild(el);setTimeout(()=>{if(el.parentNode)el.remove();},4200);
}
maintainBots(){
let bots=0;
this.snakes=this.snakes.filter(s=>{
if(s.isPlayer)return true;
if(s.dead)return false;
bots++; return true;
});
if(bots<this._botTarget)this.spawnBot();
}
updateHUD(){
if(!this.player)return;
const sc=this.player.score;
$('h-score').textContent=sc;
const now=performance.now();
if(!this._hudT||now-this._hudT>200){this._hudT=now;this._updateLB();}
}
_updateLB(){
if(!this.player)return;
const sc=this.player.score;
if(sc >= 1000 && !Prestige.isUnlocked()){
Prestige.unlock();
this._showPrestigeNotif();
}
const badge=$('prestige-badge');
if(badge) badge.style.display = Prestige.isUnlocked() ? 'flex' : 'none';
const sorted=[...this.snakes].filter(s=>!s.dead).sort((a,b)=>b.score-a.score);
const rank=sorted.findIndex(s=>s.id==='player')+1;
if(rank>0){this.bestRank=Math.min(this.bestRank,rank);$('h-rank').textContent='#'+rank}
$('h-boost').style.width=(this.player.energy*100)+'%';
const list=$('lb-list');list.innerHTML='';
sorted.slice(0,10).forEach((s,i)=>{
const li=document.createElement('li');
li.className=s.isPlayer?'me':'';
const dotStyle=s.isRainbow
? `background:conic-gradient(#ff0080,#ff8000,#ffff00,#00ff80,#0080ff,#ff0080)`
: `background:${s.liveHC}`;
li.innerHTML=`<span class="lb-n">${i+1}</span><span class="lb-dot" style="${dotStyle}"></span><span class="lb-nm">${s.isRainbow?'👑 ':' '}${s.name}</span><span class="lb-sc">${s.score}</span>`;
list.appendChild(li);
});
}
_showPrestigeNotif(){
const el=$('prestige-notif');
if(!el)return;
el.classList.add('show');
el.classList.remove('hide');
setTimeout(()=>{
el.classList.add('hide');
el.classList.remove('show');
}, 4000);
}
}
const UI = {
IDS:['music-screen','platform-screen','menu-screen','game-screen','death-screen','pause-screen'],
isMobile: false,
show(id){this.IDS.forEach(s=>{const el=$(s);el.style.display=s===id?'flex':'none';el.classList.toggle('active',s===id)})},
showDeath(score,rank,time){$('d-score').textContent=score;$('d-rank').textContent='#'+rank;$('d-time').textContent=time+'s';this.show('death-screen');setTimeout(()=>FakeLB.render(),100);},
buildStars(){
['stars','stars-p'].forEach(id=>{
const c=$(id); if(!c)return;
for(var i=0;i<130;i++){
var s=document.createElement('div'),sz=Math.random()*2.5+.5;
s.className='star';
s.style.cssText='left:'+Math.random()*100+'%;top:'+Math.random()*100+'%;width:'+sz+'px;height:'+sz+'px;--d:'+(Math.random()*3+1).toFixed(1)+'s;animation-delay:'+(Math.random()*3).toFixed(1)+'s';
c.appendChild(s);
}
});
},
initPlatform(){
var self=this;
$('pc-btn').addEventListener('click',function(){
self.isMobile=false;
document.body.classList.remove('mobile-mode');
self.show('menu-screen');
});
$('mobile-btn').addEventListener('click',function(){
self.isMobile=true;
document.body.classList.add('mobile-mode');
self.show('menu-screen');
});
},
initJoystick(){
var zone=$('joystick-zone');
var base=$('joystick-base');
var knob=$('joystick-knob');
var boostBtn=$('boost-btn-mobile');
if(!zone||!base||!knob)return;
var active=false, startX=0, startY=0;
var baseRect=null;
var joyX=0, joyY=0;
var baseR=0;
function getBaseRect(){return base.getBoundingClientRect();}
zone.addEventListener('touchstart',function(e){
e.preventDefault();
for(var i=0;i<e.changedTouches.length;i++){
var t=e.changedTouches[i];
if(!active){
active=true; baseRect=getBaseRect();
baseR=baseRect.width/2;
startX=baseRect.left+baseR; startY=baseRect.top+baseR;
var bx=t.clientX, by=t.clientY;
base.style.left=(bx-baseR)+'px'; base.style.bottom='';base.style.top=(by-baseR)+'px';
baseRect=getBaseRect(); startX=bx; startY=by;
}
}
},{passive:false});
zone.addEventListener('touchmove',function(e){
e.preventDefault();
if(!active)return;
var t=e.touches[0];
var dx=t.clientX-startX, dy=t.clientY-startY;
var dist=Math.sqrt(dx*dx+dy*dy);
var max=baseR*0.8;
if(dist>max){dx=dx/dist*max;dy=dy/dist*max;}
joyX=dx/max; joyY=dy/max;
knob.style.transform='translate(calc(-50% + '+dx+'px), calc(-50% + '+dy+'px))';
if(window.G&&window.G.player&&!window.G.player.dead){
window.G._joyX=joyX; window.G._joyY=joyY;
}
},{passive:false});
function endJoy(){
active=false; joyX=0; joyY=0;
knob.style.transform='translate(-50%,-50%)';
base.style.left=''; base.style.top=''; base.style.bottom='';
if(window.G){window.G._joyX=0;window.G._joyY=0;}
}
zone.addEventListener('touchend',endJoy);
zone.addEventListener('touchcancel',endJoy);
if(boostBtn){
boostBtn.addEventListener('touchstart',function(e){
e.preventDefault(); boostBtn.classList.add('active');
if(window.G)window.G.boosting=true;
},{passive:false});
boostBtn.addEventListener('touchend',function(){
boostBtn.classList.remove('active');
if(window.G)window.G.boosting=false;
});
}
},
getConfig(){
let skin=document.querySelector('.skin-opt.sel')?.dataset.skin||'green';
if(skin==='rainbow'&&!Prestige.isUnlocked()) skin='green';
return{
name:$('inp-name').value.trim()||'Joueur',
skin,
diff:document.querySelector('.diff-opt.sel')?.dataset.diff||'normal',
};
},
startGame(cfg){
this.show('game-screen');
window.G=new Game();
window.G.start(cfg.name,cfg.skin,cfg.diff);
},
init(){
this.IDS.forEach(s=>{const el=$(s);if(el){el.style.display='none';el.classList.remove('active')}});
this.show('platform-screen');
this.buildStars();
this.initPlatform();
this.initJoystick();
document.querySelectorAll('.skin-opt').forEach(opt=>{
opt.addEventListener('click',()=>{
if(opt.dataset.skin==='rainbow'&&!Prestige.isUnlocked()) return;
document.querySelectorAll('.skin-opt').forEach(o=>o.classList.remove('sel'));
opt.classList.add('sel');
});
});
document.querySelectorAll('.diff-opt').forEach(opt=>{
opt.addEventListener('click',()=>{
document.querySelectorAll('.diff-opt').forEach(o=>o.classList.remove('sel','easy','normal','hard'));
opt.classList.add('sel', opt.dataset.diff);
});
});
const selDiff=document.querySelector('.diff-opt.sel');
if(selDiff)selDiff.classList.add(selDiff.dataset.diff);
$('btn-play').addEventListener('click',()=>this.startGame(this.getConfig()));
$('inp-name').addEventListener('keydown',e=>{if(e.key==='Enter')$('btn-play').click()});
$('btn-retry').addEventListener('click',()=>this.startGame(this.getConfig()));
$('btn-menu').addEventListener('click',()=>{this.show('menu-screen');FakeLB.render();});
$('btn-resume').addEventListener('click',()=>{if(window.G)window.G.togglePause()});
$('btn-pmenu').addEventListener('click',()=>{if(window.G)window.G.running=false;this.show('menu-screen')});
}
};
const Admin = {
CODE: '2210',
godMode: false,
frozen: false,
boostInf: false,
notify(msg){
var n = document.getElementById('adm-notif');
n.textContent = msg; n.classList.add('show');
clearTimeout(Admin._nt);
Admin._nt = setTimeout(function(){ n.classList.remove('show'); }, 2200);
},
initLogin(){
var digits = ['adm-d0','adm-d1','adm-d2','adm-d3'];
var self = this;
document.getElementById('btn-admin').addEventListener('click', function(){
if(!window.G || !window.G.running) return;
document.getElementById('admin-login').classList.add('open');
document.getElementById('adm-d0').focus();
digits.forEach(function(id){ var el=document.getElementById(id); el.value=''; el.classList.remove('filled'); });
document.getElementById('adm-err').classList.remove('show');
});
digits.forEach(function(id, i){
var el = document.getElementById(id);
el.addEventListener('input', function(){
if(el.value){ el.classList.add('filled'); if(i<3) document.getElementById(digits[i+1]).focus(); }
var code = digits.map(function(d){ return document.getElementById(d).value; }).join('');
if(code.length === 4){
if(code === self.CODE){
document.getElementById('admin-login').classList.remove('open');
document.getElementById('admin-overlay').classList.add('open');
document.getElementById('adm-err').classList.remove('show');
if(window.G&&window.G.running&&!window.G.paused){window.G.paused=true;Music.pause();}
} else {
document.getElementById('adm-err').classList.add('show');
setTimeout(function(){
digits.forEach(function(d){ var e=document.getElementById(d); e.value=''; e.classList.remove('filled'); });
document.getElementById('adm-d0').focus();
}, 700);
}
}
});
el.addEventListener('keydown', function(e){
if(e.key==='Backspace'&&!el.value&&i>0){ document.getElementById(digits[i-1]).focus(); }
if(e.key==='Escape'){
document.getElementById('admin-login').classList.remove('open');
}
});
});
},
initPanel(){
var self = this;
document.getElementById('adm-close').addEventListener('click', function(){
document.getElementById('admin-overlay').classList.remove('open');
Admin.startCountdown();
});
document.getElementById('adm-set-size').addEventListener('click', function(){
var g=window.G; if(!g||!g.player||g.player.dead) return;
var target = parseInt(document.getElementById('adm-size-val').value)||100;
var cur = g.player.len;
if(target > cur) g.player.grow(target-cur);
else if(target < cur){ for(var i=0;i<cur-target;i++) g.player.segs.pop(); g.player.score=g.player.len; }
self.notify('Taille définie : ' + target);
});
document.getElementById('adm-set-speed').addEventListener('click', function(){
var g=window.G; if(!g||!g.player) return;
g.player.speed = parseInt(document.getElementById('adm-speed-val').value)||155;
self.notify('Vitesse : ' + g.player.speed);
});
document.getElementById('adm-tp').addEventListener('click', function(){
var g=window.G; if(!g||!g.player) return;
var x=parseInt(document.getElementById('adm-tp-x').value)||0;
var y=parseInt(document.getElementById('adm-tp-y').value)||0;
g.player._tp(x,y);
self.notify('Téléporté en ('+x+', '+y+')');
});
document.getElementById('adm-center').addEventListener('click', function(){
var g=window.G; if(!g||!g.player) return;
g.player._tp(0,0); self.notify('Téléporté au centre');
});
document.getElementById('adm-god').addEventListener('click', function(){
self.godMode = !self.godMode;
document.getElementById('adm-god').textContent = self.godMode ? '⚡ Mode Dieu ON' : '⚡ Mode Dieu';
document.getElementById('adm-god').style.borderColor = self.godMode ? '#ffd700' : '';
self.notify(self.godMode ? '⚡ Mode Dieu activé' : 'Mode Dieu désactivé');
});
document.getElementById('adm-prestige').addEventListener('click', function(){
Prestige.unlock(); self.notify('👑 Prestige forcé !');
});
document.getElementById('adm-regen').addEventListener('click', function(){
self.boostInf = !self.boostInf;
document.getElementById('adm-regen').textContent = self.boostInf ? '🔋 Boost ∞ ON' : '🔋 Boost ∞';
document.getElementById('adm-regen').style.borderColor = self.boostInf ? '#ffcc00' : '';
self.notify(self.boostInf ? 'Boost infini ON' : 'Boost infini OFF');
});
document.getElementById('adm-kill-all').addEventListener('click', function(){
var g=window.G; if(!g) return;
var killed=0;
g.snakes.forEach(function(s){ if(!s.isPlayer&&!s.dead){ g.killSnake(s); killed++; } });
self.notify('💀 ' + killed + ' bots éliminés');
});
document.getElementById('adm-kill-near').addEventListener('click', function(){
var g=window.G; if(!g||!g.player) return;
var px=g.player.head.x, py=g.player.head.y, killed=0;
g.snakes.forEach(function(s){
if(!s.isPlayer&&!s.dead){
var dx=s.head.x-px,dy=s.head.y-py;
if(dx*dx+dy*dy < 600*600){ g.killSnake(s); killed++; }
}
});
self.notify('🎯 ' + killed + ' bots tués autour');
});
document.getElementById('adm-freeze').addEventListener('click', function(){
self.frozen=true;
document.getElementById('adm-freeze').style.borderColor='#00ccff';
self.notify('🧊 Bots gelés');
});
document.getElementById('adm-unfreeze').addEventListener('click', function(){
self.frozen=false;
document.getElementById('adm-freeze').style.borderColor='';
var g=window.G; if(g) g.snakes.forEach(function(s){
if(!s.isPlayer) s.speed = _DIFF.speed + U.rand(-15,15);
});
self.notify('▶️ Bots dégelés');
});
document.getElementById('adm-set-bots').addEventListener('click', function(){
var g=window.G; if(!g) return;
var nb=parseInt(document.getElementById('adm-bots-val').value)||22;
g._botTarget=nb; self.notify('Nb bots cible : ' + nb);
});
document.getElementById('adm-spawn-big').addEventListener('click', function(){
var g=window.G; if(!g) return;
var b=g.spawnBot(); b.grow(300); self.notify('🐍 Géant spawné !');
});
document.getElementById('adm-clear-food').addEventListener('click', function(){
var g=window.G; if(!g) return;
g.food.items=[]; self.notify('Nourriture vidée');
});
document.getElementById('adm-flood-food').addEventListener('click', function(){
var g=window.G; if(!g) return;
for(var i=0;i<800;i++) g.food.spawn();
self.notify('🍎 +800 nourritures !');
});
document.getElementById('adm-zoom-in').addEventListener('click', function(){
var g=window.G; if(!g) return; g.rdr.zoom=Math.min(g.rdr.zoom*1.4,3); self.notify('Zoom +');
});
document.getElementById('adm-zoom-out').addEventListener('click', function(){
var g=window.G; if(!g) return; g.rdr.zoom=Math.max(g.rdr.zoom*.7,.15); self.notify('Zoom -');
});
document.getElementById('adm-zoom-reset').addEventListener('click', function(){
var g=window.G; if(!g) return; g.rdr.zoom=1; self.notify('Zoom réinitialisé');
});
},
tick(){
var g=window.G; if(!g||!g.player||g.player.dead) return;
if(Admin.boostInf) g.player.energy=1;
if(Admin.frozen) g.snakes.forEach(function(s){ if(!s.isPlayer) s.speed=0; });
},
startCountdown(){
var el=document.getElementById('adm-countdown');
var num=document.getElementById('adm-cd-num');
var n=3;
el.classList.add('show');
num.textContent=n;
num.style.animation='none'; void num.offsetWidth; num.style.animation='';
var iv=setInterval(function(){
n--;
if(n>0){
num.textContent=n;
num.style.animation='none'; void num.offsetWidth; num.style.animation='';
} else {
el.classList.remove('show');
clearInterval(iv);
if(window.G&&window.G.running&&window.G.paused){window.G.paused=false;window.G.lastT=performance.now();Music.resume();requestAnimationFrame(function(t){window.G.loop(t);});}
}
},1000);
},
init(){
this.initLogin();
this.initPanel();
}
};
document.addEventListener('DOMContentLoaded',()=>{UI.init();Prestige.init();FakeLB.init();Music.init();Admin.init();});